import * as v from "valibot";

const authConfigSchema = v.pipe(
  v.object({
    mode: v.optional(v.picklist(["supabase", "mock"]), "supabase"),
    email: v.optional(v.string()),
    password: v.optional(v.string()),
  }),
  v.transform(({ mode, email, password }) =>
    mode === "mock"
      ? { isMocked: true, email, password }
      : { isMocked: false },
  ),
  v.variant("isMocked", [
    v.object({
      isMocked: v.literal(true),
      email: v.pipe(v.string(), v.email()),
      password: v.pipe(v.string(), v.minLength(6)),
    }),
    v.object({
      isMocked: v.literal(false),
    }),
  ]),
);

export type AuthConfig = v.InferOutput<typeof authConfigSchema>;

export function getAuthConfig(): AuthConfig {
  return v.parse(authConfigSchema, {
    mode: process.env.NEXT_PUBLIC_AUTH_MODE,
    email: process.env.NEXT_PUBLIC_MOCK_AUTH_EMAIL,
    password: process.env.NEXT_PUBLIC_MOCK_AUTH_PASSWORD,
  });
}

